batch_size = 8
total = len(clubs)
inserted = 0
errors = 0

for i in range(0, total, batch_size):
    batch = clubs[i:i+batch_size]
    values_parts = []

    for c in batch:
        name, address, lat, lon, pc_count, rating, tier, has_ps, has_vr, desc, price, reviews, phone, telegram = c
        name_esc = name.replace("'", "''")
        address_esc = address.replace("'", "''")
        desc_esc = desc.replace("'", "''")
        phone_sql = f"'{phone}'" if phone else "NULL"
        telegram_sql = f"'{telegram}'" if telegram else "NULL"
        has_ps_sql = "true" if has_ps else "false"
        has_vr_sql = "true" if has_vr else "false"

        val = f"(gen_random_uuid(), '{name_esc}', '{address_esc}', {lat}, {lon}, '{{}}', '{WH24}'::jsonb, {pc_count}, {rating}, '{{}}'::jsonb, 'active', '{tier}', now(), {has_ps_sql}, {has_vr_sql}, 0, {pc_count}, {lat}, {lon}, '{desc_esc}', {price}, {reviews}, {phone_sql}, {telegram_sql})"
        values_parts.append(val)

    sql = f"INSERT INTO public.clubs (id, name, address, lat, lon, photos, working_hours, pc_count, rating, payout_details, status, tier, created_at, has_playstation, has_vr, current_occupancy, total_capacity, latitude, longitude, description, price_per_hour, review_count, contact_phone, contact_telegram) VALUES {', '.join(values_parts)};"

    result = run_sql(sql)
    inserted += len(batch)

    if "error" in result.lower() or "message" in result.lower():
        errors += 1
        print(f"Batch {i//batch_size + 1}: ERROR - {result[:200]}")
    else:
        print(f"Batch {i//batch_size + 1}: OK ({inserted}/{total})")

print(f"\nInserted {inserted} clubs total, {errors} errors")
print("\n=== Final count ===")
print(run_sql("SELECT count(*) as total FROM public.clubs;"))
